    def myAtoi(self, s):
        i = 0
        n = len(s)
        while i < n and s[i] == ' ':
            i += 1
        sign = 1
        if i < n and s[i] in '+-':
            if s[i] == '-':
                sign = -1
            i += 1
        digits = ''
        while i < n and s[i].isdigit():
            digits += s[i]
            i += 1
        if not digits:
            return 0
        val = sign * int(digits)
        if val < -2147483648:
            return -2147483648
        if val > 2147483647:
            return 2147483647
        return val

