        while i < n and s[i] == ' ':
            i += 1
        sign = 1
        if i < n and (s[i] == '+' or s[i] == '-'):
            sign = -1 if s[i] == '-' else 1
            i += 1
        num = 0
        started = False
        while i < n and '0' <= s[i] <= '9':
            started = True
            num = num * 10 + (ord(s[i]) - 48)
            i += 1
        if not started:
            return 0
        num *= sign
        if num < INT_MIN:
            return INT_MIN
        if num > INT_MAX:
            return INT_MAX
        return num

