var myAtoi = function(s) {
    const INT_MIN = -2147483648, INT_MAX = 2147483647;
    let i = 0;
    const n = s.length;
    while (i < n && s[i] === ' ') i++;
    let sign = 1;
    if (i < n && (s[i] === '+' || s[i] === '-')) {
        sign = s[i] === '-' ? -1 : 1;
        i++;
    }
    let num = 0;
    let started = false;
    while (i < n && s[i] >= '0' && s[i] <= '9') {
        started = true;
        num = num * 10 + (s.charCodeAt(i) - 48);
        i++;
    }
    if (!started) return 0;
    num *= sign;
    if (num < INT_MIN) return INT_MIN;
    if (num > INT_MAX) return INT_MAX;
    return num;
};
